package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Files, Paths}
import scala.util.control.NonFatal

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val uploadsRoot = Paths.get("uploads").toAbsolutePath.normalize()

  def serve(filename: String): Action[AnyContent] = Action {
    val requestedPath = uploadsRoot.resolve(filename).normalize()

    if (!requestedPath.startsWith(uploadsRoot)) {
      Forbidden("Invalid file path")
    } else {
      val file = requestedPath.toFile
      if (!file.exists() || !file.isFile) {
        NotFound("File not found")
      } else {
        try {
          val source = Source.fromFile(s"uploads/$filename")
          try {
            Ok.sendEntity(source.mkString).as("application/octet-stream")
          } finally {
            source.close()
          }
        } catch {
          case NonFatal(_) =>
            InternalServerError("Unable to read file")
        }
      }
    }
  }
}